member.example:
Bind the CanvasGroup blocksRaycasts property using a serialized binder field — the target CanvasGroup is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private CanvasGroupBlocksRaycastsBinder _blocksRaycasts;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _blocksRaycasts;
    }


Bind the CanvasGroup blocksRaycasts property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private CanvasGroup _canvasGroup;
        
        private CanvasGroupBlocksRaycastsBinder BlocksRaycasts =>
            new(_canvasGroup);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _blocksRaycasts;
    }
